-- Meeting: Tristan Pelligrino and Christine Schulz (Encamp) (2026-01-14 18:30:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '4cf099a8-6df8-4d70-a3eb-053cb48f9f1f',
    '2026-01-14 18:30:00+00',
    'fireflies',
    '01KEF078WSDX9DTMHAA51PVEFK',
    'Tristan Pelligrino and Christine Schulz (Encamp)',
    '{"Nina Belina","Jenny Beightol","Tristan Pelligrino","Christine Schulz"}'::text[],
    1095,
    'https://us02web.zoom.us/j/82201978387?pwd=7Ll8Nqvnxxdm75d30YGqXzbQb6PuX9.1',
    '{"id":"01KEF078WSDX9DTMHAA51PVEFK","title":"Tristan Pelligrino and Christine Schulz (Encamp)","summary":{"notes":"## **Website Backend Functionality and Structure**\n\nThe team confirmed the new website backend uses **Elementor with a lightweight WordPress theme** to offer flexible and efficient content updates (01:55).\n\n- **Tristan Pelligrino** detailed the use of Elementor’s built-in components like image carousels and global styling for fonts and colors, minimizing custom code and ensuring easy edits.\n- Global CSS handles site-wide style changes, as **Nina Belina** noted, allowing consistent updates across pages without manual repetition.\n- Standard WordPress features such as version control require **Elementor Pro** for full functionality, and password protection will be handled via lightweight plugins layered on top of the core theme.\n- The approach targets marketing team autonomy, enabling quick changes without deep development, improving over prior custom field complexities (16:15).\n\n## **Plugin Integration and Licensing**\n\nKey plugins like **Yoast SEO** and **Elementor Pro** are planned to be added before site launch, requiring client purchase of licenses (06:11).\n\n- Licenses are domain-specific and must be reactivated immediately after pushing from staging to live to avoid downtime, a process Tristan confirmed will be handled within seconds of launch.\n- Yoast will manage SEO titles, tags, metadata, and 301 redirects cleanly, aligning with the SEO strategy and simplifying ongoing site management.\n- The team will maintain a punch list to track remaining plugin installs and miscellaneous final tasks, ensuring nothing is missed before launch (07:37).\n\n## **Product Page Flexibility and Roadmap Alignment**\n\nThe website structure allows easy expansion of product sections, supporting the rollout of the **compliance platform page** ahead of its early Q2 launch (09:14).\n\n- Jenny Beightol confirmed the current build enables adding new product containers seamlessly by duplicating existing components and updating content.\n- Nina emphasized the ability to add specific blocks like text or images, allowing the marketing team to adapt pages as the product roadmap evolves.\n- Tristan assured that the website will support incremental updates without blocking the live site launch, aligning product development timelines with marketing needs.\n\n## **HubSpot Form Integration and Access Management**\n\nHubSpot forms will be integrated using **HTML embed codes** placed in Elementor containers, allowing styling to be controlled primarily within HubSpot (11:21).\n\n- Nina recommended granting the HubSpot consultant WordPress staging access once pages are stable to manage form setup directly, ensuring proper workflow alignment.\n- Tristan highlighted the importance of coordinating timing to avoid content conflicts during development, as page checkout locks editing for others.\n- User management considerations arose because staging user additions will overwrite live users upon pushing, requiring careful coordination to avoid data loss (15:18).\n\n## **Launch Preparation and Post-Launch Support**\n\nThe team plans a coordinated effort to complete final tasks and ensure smooth transition to live, with clear responsibilities and timelines (07:37).\n\n- Tristan will provide a detailed punch list of remaining items, including plugin activations and miscellaneous fixes, helping Jenny’s team track progress.\n- License reactivations for Elementor and Yoast will occur immediately after going live to prevent any functional gaps.\n- The site is expected to empower the marketing team for quick content updates post-launch, reducing reliance on developers and improving agility (16:15).","outline":null,"keywords":["Elementor","WordPress backend","HubSpot forms","Yoast SEO","password protection plugin","staging environment"],"overview":"- **Website Structure:** New backend uses Elementor with a lightweight WordPress theme for flexible, easy content updates.  \n- **License Requirement:** Yoast SEO and Elementor Pro licenses must be purchased for domain-specific functionality before launch.  \n- **Product Page Flexibility:** Structure allows seamless addition of product sections ahead of early Q2 compliance platform launch.  \n- **HubSpot Integration:** HubSpot forms will be embedded in Elementor, with access management planned to prevent content conflicts.  \n- **Launch Prep:** Detailed punch list for final tasks supports smooth transition to live site, enhancing post-launch marketing agility.","action_items":"\n**Tristan Pelligrino**\nProvide punch list of final tasks and action items for go-live to client marketing team (07:37)\nSet up user access for HubSpot consultant on staging site after development lock and communicate timing to Christine and team (14:49)\nAssist with embedding HubSpot forms using HTML embed codes; ensure container responsiveness and styling compatibility (16:40)\nReactivate Elementor and Yoast plugin licenses immediately after site push to live environment (08:27)\n\n**Christine Schulz**\nShare HubSpot consultant contact details and form embed info with Tristan and Nina to setup access for staging environment (14:49)\n\n**Nina Belina**\nCoordinate timing of locking pages for form integration and manage feedback implementation including animation removal (14:49)\nAssist in granting WordPress access to HubSpot consultant for form integration post-development completion (14:49)\n"},"duration":18.25,"speakers":[{"id":0,"name":"Nina Belina"},{"id":1,"name":"Jenny Beightol"},{"id":2,"name":"Tristan Pelligrino"},{"id":3,"name":"Christine Schulz"}],"sentences":[{"text":"Good.","index":0,"end_time":0.28,"speaker_id":0,"start_time":0.08,"speaker_name":"Nina Belina"},{"text":"We''re doing great.","index":1,"end_time":1.36,"speaker_id":1,"start_time":0.28,"speaker_name":"Jenny Beightol"},{"text":"How are you?","index":2,"end_time":2.32,"speaker_id":1,"start_time":1.68,"speaker_name":"Jenny Beightol"},{"text":"Doing all right.","index":3,"end_time":3.52,"speaker_id":2,"start_time":2.64,"speaker_name":"Tristan Pelligrino"},{"text":"Doing all right, yeah.","index":4,"end_time":4.6,"speaker_id":2,"start_time":3.52,"speaker_name":"Tristan Pelligrino"},{"text":"Thanks for setting this time up.","index":5,"end_time":6.68,"speaker_id":2,"start_time":4.6,"speaker_name":"Tristan Pelligrino"},{"text":"Christine.","index":6,"end_time":7.16,"speaker_id":2,"start_time":6.68,"speaker_name":"Tristan Pelligrino"},{"text":"I know you had some questions in an email and wanted to take some time today, see what we can do to help you.","index":7,"end_time":15.32,"speaker_id":2,"start_time":7.16,"speaker_name":"Tristan Pelligrino"},{"text":"I didn''t see an agenda sent over.","index":8,"end_time":17.04,"speaker_id":2,"start_time":15.32,"speaker_name":"Tristan Pelligrino"},{"text":"So, you know, where.","index":9,"end_time":18.16,"speaker_id":2,"start_time":17.04,"speaker_name":"Tristan Pelligrino"},{"text":"Where did you feel like the best place would be to start?","index":10,"end_time":20.8,"speaker_id":2,"start_time":18.16,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, so I really just wanted to, like, I know we''ve been working on the front end of the website and the design piece of it.","index":11,"end_time":28.8,"speaker_id":3,"start_time":21.52,"speaker_name":"Christine Schulz"},{"text":"My background is more on the back end of the website, which I know you''re working on.","index":12,"end_time":34.47,"speaker_id":3,"start_time":30.19,"speaker_name":"Christine Schulz"},{"text":"I know it''s not done.","index":13,"end_time":35.39,"speaker_id":3,"start_time":34.47,"speaker_name":"Christine Schulz"},{"text":"I''m not trying to, like, pick it apart or anything, but, like, I would really just kind of like to see how the functionality is being set up with Elementor and just kind of understand, like, how the structure of the back end of the website is working, like, from a WordPress standpoint, not like how it''s hosted or anything like that, just to get, like, a better understanding.","index":14,"end_time":59.84,"speaker_id":3,"start_time":35.87,"speaker_name":"Christine Schulz"},{"text":"Because functionality, obviously was one of the things that we were really looking for, and I know the Elementor plugin is very flexible, but I just kind of wanted to get a better understanding of, like, how it''s being integrated with the website, like, what kind of functionality is it going to have, and making sure, like, some of the little nuanced things that we''re struggling with on the current website are addressed with the new site going forward.","index":15,"end_time":85.69,"speaker_id":3,"start_time":59.84,"speaker_name":"Christine Schulz"},{"text":"Yeah.","index":16,"end_time":87.29,"speaker_id":2,"start_time":86.81,"speaker_name":"Tristan Pelligrino"},{"text":"So what''s the best way for me to.","index":17,"end_time":90.01,"speaker_id":2,"start_time":87.29,"speaker_name":"Tristan Pelligrino"},{"text":"To describe that?","index":18,"end_time":91.17,"speaker_id":2,"start_time":90.01,"speaker_name":"Tristan Pelligrino"},{"text":"I guess I could.","index":19,"end_time":92.77,"speaker_id":2,"start_time":91.17,"speaker_name":"Tristan Pelligrino"},{"text":"I could show you what it looks like.","index":20,"end_time":94.65,"speaker_id":2,"start_time":92.77,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, if that.","index":21,"end_time":96.57,"speaker_id":2,"start_time":94.97,"speaker_name":"Tristan Pelligrino"},{"text":"If that helps.","index":22,"end_time":97.609,"speaker_id":2,"start_time":96.57,"speaker_name":"Tristan Pelligrino"},{"text":"Is there something specific?","index":23,"end_time":99.45,"speaker_id":2,"start_time":98.25,"speaker_name":"Tristan Pelligrino"},{"text":"Like, have you worked with Elementor before?","index":24,"end_time":101.33,"speaker_id":2,"start_time":99.45,"speaker_name":"Tristan Pelligrino"},{"text":"Are you pretty familiar with how it works?","index":25,"end_time":103.25,"speaker_id":2,"start_time":101.33,"speaker_name":"Tristan Pelligrino"},{"text":"Okay, I can do that.","index":26,"end_time":107.21,"speaker_id":2,"start_time":103.25,"speaker_name":"Tristan Pelligrino"},{"text":"I just have the homepage pulled up.","index":27,"end_time":109.7,"speaker_id":2,"start_time":108.3,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, I''ll show you how the different components are set up.","index":28,"end_time":112.3,"speaker_id":2,"start_time":109.7,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":29,"end_time":115.5,"speaker_id":3,"start_time":115.1,"speaker_name":"Christine Schulz"},{"text":"Because I know we also have our HubSpot consultant who was asking about, like, how to set up the HubSpot forms and things like that, and, like, if he should be doing that or, like, because I know we have to test a lot of things.","index":30,"end_time":129.1,"speaker_id":3,"start_time":115.5,"speaker_name":"Christine Schulz"},{"text":"Yeah.","index":31,"end_time":131.02,"speaker_id":2,"start_time":130.46,"speaker_name":"Tristan Pelligrino"},{"text":"So, yeah, we could talk about form integration and things.","index":32,"end_time":134.14,"speaker_id":2,"start_time":131.66,"speaker_name":"Tristan Pelligrino"},{"text":"That stuff''s pretty straightforward.","index":33,"end_time":136.01,"speaker_id":2,"start_time":134.81,"speaker_name":"Tristan Pelligrino"},{"text":"But as.","index":34,"end_time":136.77,"speaker_id":2,"start_time":136.25,"speaker_name":"Tristan Pelligrino"},{"text":"As far as Elementor, I mean, we have pretty classic header and footer construction.","index":35,"end_time":143.77,"speaker_id":2,"start_time":136.77,"speaker_name":"Tristan Pelligrino"},{"text":"So this is, for instance, the.","index":36,"end_time":145.77,"speaker_id":2,"start_time":143.77,"speaker_name":"Tristan Pelligrino"},{"text":"The homepage here.","index":37,"end_time":146.77,"speaker_id":2,"start_time":145.77,"speaker_name":"Tristan Pelligrino"},{"text":"And you can see that pretty much all of these are individual components that, you know, you can go in, you know, adjust and everything from there.","index":38,"end_time":157.21,"speaker_id":2,"start_time":146.77,"speaker_name":"Tristan Pelligrino"},{"text":"So, you know, a lot of the functionality, like, if we look at a carousel component, we''re Using Elementor''s built in image carousel, for example, you know, we have global styling set up as well.","index":39,"end_time":173.78,"speaker_id":2,"start_time":157.53,"speaker_name":"Tristan Pelligrino"},{"text":"So a lot of the headings, no font style, font weight, colors, all that stuff are in a global style sheet.","index":40,"end_time":183.54,"speaker_id":2,"start_time":174.66,"speaker_name":"Tristan Pelligrino"},{"text":"So not a whole lot of custom code.","index":41,"end_time":187.51,"speaker_id":2,"start_time":184.26,"speaker_name":"Tristan Pelligrino"},{"text":"There are some little pieces that we''ve put in, put out.","index":42,"end_time":190.35,"speaker_id":2,"start_time":187.51,"speaker_name":"Tristan Pelligrino"},{"text":"Some of the animation components have changed and evolved, but for the most part, I mean, everything is built on the front end.","index":43,"end_time":196.95,"speaker_id":2,"start_time":190.43,"speaker_name":"Tristan Pelligrino"},{"text":"You know, we have a standard theme that we''re building on top of that''s very lightweight.","index":44,"end_time":200.79,"speaker_id":2,"start_time":196.95,"speaker_name":"Tristan Pelligrino"},{"text":"But you know, this, this approach is intended to give you all the flexibility to come in here, change a, you know, a widget or a title or a statistic in a pretty efficient way.","index":45,"end_time":215.15,"speaker_id":2,"start_time":200.79,"speaker_name":"Tristan Pelligrino"},{"text":"Awesome.","index":46,"end_time":218.3,"speaker_id":3,"start_time":217.9,"speaker_name":"Christine Schulz"},{"text":"And for some of the global changes, they''re usually done in the css.","index":47,"end_time":223.26,"speaker_id":0,"start_time":219.02,"speaker_name":"Nina Belina"},{"text":"So, for example, I also mentioned to Kylie that if she sees something that for example, you like and it''s very specific to one page, we can make it a global change for all pages to be the same.","index":48,"end_time":235.98,"speaker_id":0,"start_time":223.5,"speaker_name":"Nina Belina"},{"text":"Cool.","index":49,"end_time":237.58,"speaker_id":2,"start_time":237.1,"speaker_name":"Tristan Pelligrino"},{"text":"Kind of some standard things that I feel like should be a part of every website, but for some reason it''s not on WordPress.","index":50,"end_time":250.07,"speaker_id":3,"start_time":242.87,"speaker_name":"Christine Schulz"},{"text":"But things like version control of the web page, like and like password protecting pages.","index":51,"end_time":259.43,"speaker_id":3,"start_time":251.51,"speaker_name":"Christine Schulz"},{"text":"I know we do a lot of that with a lot of our customers and clients.","index":52,"end_time":262.95,"speaker_id":3,"start_time":259.43,"speaker_name":"Christine Schulz"},{"text":"It''s like, is that capability built into the template or to the, I guess wouldn''t be the template, but the theme.","index":53,"end_time":271.75,"speaker_id":3,"start_time":263.91,"speaker_name":"Christine Schulz"},{"text":"Yeah, we don''t have that.","index":54,"end_time":274.43,"speaker_id":2,"start_time":273.27,"speaker_name":"Tristan Pelligrino"},{"text":"That would just be probably a lightweight plugin that I would suggest, you know, if you do want to password protect a page, there''s like a member plugin or just a simple content, like a gated content plugin that you could add on top of what exists now.","index":55,"end_time":292.31,"speaker_id":2,"start_time":274.43,"speaker_name":"Tristan Pelligrino"},{"text":"That''s probably how I would handle it.","index":56,"end_time":294.23,"speaker_id":2,"start_time":292.71,"speaker_name":"Tristan Pelligrino"},{"text":"It''s not going to be part of the core theme.","index":57,"end_time":296.57,"speaker_id":2,"start_time":294.65,"speaker_name":"Tristan Pelligrino"},{"text":"It would be something that would get layered in on top version control, something.","index":58,"end_time":302.41,"speaker_id":2,"start_time":296.81,"speaker_name":"Tristan Pelligrino"},{"text":"Let''s see, where is that?","index":59,"end_time":304.73,"speaker_id":2,"start_time":303.29,"speaker_name":"Tristan Pelligrino"},{"text":"I''m trying to remember.","index":60,"end_time":311.21,"speaker_id":2,"start_time":310.01,"speaker_name":"Tristan Pelligrino"},{"text":"I think it might be the upper left corner, the clock.","index":61,"end_time":318.25,"speaker_id":0,"start_time":313.93,"speaker_name":"Nina Belina"},{"text":"There it is.","index":62,"end_time":319.61,"speaker_id":2,"start_time":318.89,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":63,"end_time":320.49,"speaker_id":2,"start_time":320.01,"speaker_name":"Tristan Pelligrino"},{"text":"Sorry.","index":64,"end_time":321.01,"speaker_id":2,"start_time":320.57,"speaker_name":"Tristan Pelligrino"},{"text":"Thanks, Nina.","index":65,"end_time":321.77,"speaker_id":2,"start_time":321.01,"speaker_name":"Tristan Pelligrino"},{"text":"Changes all the time.","index":66,"end_time":323.47,"speaker_id":2,"start_time":322.75,"speaker_name":"Tristan Pelligrino"},{"text":"So, yeah, so this is, you know, any revisions that we want to, you know, post and, and track it would be here.","index":67,"end_time":331.87,"speaker_id":2,"start_time":323.47,"speaker_name":"Tristan Pelligrino"},{"text":"So we can, we can turn this on.","index":68,"end_time":336.51,"speaker_id":2,"start_time":334.75,"speaker_name":"Tristan Pelligrino"},{"text":"But normally in development we''re not going to put that in place.","index":69,"end_time":340.03,"speaker_id":2,"start_time":336.91,"speaker_name":"Tristan Pelligrino"},{"text":"You would need the Elementor Pro plugin, I believe, which is one of the ones that we listed in the website plan.","index":70,"end_time":347.39,"speaker_id":2,"start_time":340.91,"speaker_name":"Tristan Pelligrino"},{"text":"So that and Yoast are probably two big ones that, that we normally suggest.","index":71,"end_time":351.18,"speaker_id":2,"start_time":347.71,"speaker_name":"Tristan Pelligrino"},{"text":"Yoast would give you the opportunity to put Some consistency around your SEO titles and tags and metadata for each page as well.","index":72,"end_time":359.66,"speaker_id":2,"start_time":351.18,"speaker_name":"Tristan Pelligrino"},{"text":"That also is how we would probably handle the 301 redirects using the Yoast plug.","index":73,"end_time":366.339,"speaker_id":2,"start_time":360.06,"speaker_name":"Tristan Pelligrino"},{"text":"It''s a pretty clean way to do it versus using like some of the built in WordPress functionality.","index":74,"end_time":371.26,"speaker_id":2,"start_time":366.339,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":75,"end_time":371.98,"speaker_id":3,"start_time":371.58,"speaker_name":"Christine Schulz"},{"text":"So those are or aren''t going to be with the published site.","index":76,"end_time":378.2,"speaker_id":3,"start_time":371.98,"speaker_name":"Christine Schulz"},{"text":"Is that something we''d have to do afterwards?","index":77,"end_time":380.76,"speaker_id":3,"start_time":378.44,"speaker_name":"Christine Schulz"},{"text":"Well, yeah, we''ll have to get that before we go live.","index":78,"end_time":383.72,"speaker_id":2,"start_time":380.92,"speaker_name":"Tristan Pelligrino"},{"text":"You''ll have to get a separate subscription to those plugins.","index":79,"end_time":387.28,"speaker_id":2,"start_time":384.28,"speaker_name":"Tristan Pelligrino"},{"text":"We just have typically the client buy those.","index":80,"end_time":389.88,"speaker_id":2,"start_time":387.28,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, these are very inexpensive.","index":81,"end_time":392.6,"speaker_id":2,"start_time":389.88,"speaker_name":"Tristan Pelligrino"},{"text":"Yoast is like a hundred dollars a year or something.","index":82,"end_time":395.88,"speaker_id":2,"start_time":393,"speaker_name":"Tristan Pelligrino"},{"text":"And Elemental.","index":83,"end_time":396.92,"speaker_id":2,"start_time":395.96,"speaker_name":"Tristan Pelligrino"},{"text":"I think we have Yoast on our current website, which I think we have the paid plan for.","index":84,"end_time":401.64,"speaker_id":3,"start_time":397.56,"speaker_name":"Christine Schulz"},{"text":"Yeah, you just have to.","index":85,"end_time":403.81,"speaker_id":2,"start_time":402.29,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, the one thing we''ll typically do that towards the end because even if we''re on stage and we would have to add another site, so it requires another license.","index":86,"end_time":411.49,"speaker_id":2,"start_time":404.93,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s one of the things we''ll do when we go live.","index":87,"end_time":414.53,"speaker_id":2,"start_time":411.57,"speaker_name":"Tristan Pelligrino"},{"text":"We have to.","index":88,"end_time":415.29,"speaker_id":2,"start_time":414.53,"speaker_name":"Tristan Pelligrino"},{"text":"Because the URL is different.","index":89,"end_time":416.69,"speaker_id":2,"start_time":415.29,"speaker_name":"Tristan Pelligrino"},{"text":"So Yoast recognizes staging is really just a separate domain.","index":90,"end_time":420.65,"speaker_id":2,"start_time":416.69,"speaker_name":"Tristan Pelligrino"},{"text":"So it charges you extra until you, you flip the switch and then you can install it there.","index":91,"end_time":426.69,"speaker_id":2,"start_time":420.65,"speaker_name":"Tristan Pelligrino"},{"text":"Elementor is the same thing.","index":92,"end_time":428.61,"speaker_id":2,"start_time":427.09,"speaker_name":"Tristan Pelligrino"},{"text":"Um, but you get.","index":93,"end_time":432.03,"speaker_id":2,"start_time":429.07,"speaker_name":"Tristan Pelligrino"},{"text":"So we have an agency plan, but for, for clients, I think you get like two to three domains with a pretty standard package.","index":94,"end_time":439.87,"speaker_id":2,"start_time":432.67,"speaker_name":"Tristan Pelligrino"},{"text":"And then get Elementor Pro in case you have any, you know, bugs or anything like that.","index":95,"end_time":445.51,"speaker_id":2,"start_time":440.11,"speaker_name":"Tristan Pelligrino"},{"text":"You can log tickets with them and that way you have the license and then you know the license key is attached to your WordPress environment.","index":96,"end_time":455.79,"speaker_id":2,"start_time":445.51,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":97,"end_time":457.25,"speaker_id":3,"start_time":457.01,"speaker_name":"Christine Schulz"},{"text":"And so, Tristan, this will all be part of like the actions that you send over to our team as we approach going live.","index":98,"end_time":467.41,"speaker_id":1,"start_time":457.89,"speaker_name":"Jenny Beightol"},{"text":"Yeah, we''ll have a punch list, which is something I referenced in there.","index":99,"end_time":470.89,"speaker_id":2,"start_time":468.05,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, there''s going to be a lot of, A lot of just little, little things.","index":100,"end_time":474.13,"speaker_id":2,"start_time":470.89,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":101,"end_time":474.65,"speaker_id":1,"start_time":474.21,"speaker_name":"Jenny Beightol"},{"text":"Yeah, great.","index":102,"end_time":475.33,"speaker_id":1,"start_time":474.65,"speaker_name":"Jenny Beightol"},{"text":"We have like a list that we, we work from.","index":103,"end_time":477.81,"speaker_id":2,"start_time":475.49,"speaker_name":"Tristan Pelligrino"},{"text":"But then there''s always just, I don''t know, Jenny, random things that pop up.","index":104,"end_time":482.05,"speaker_id":2,"start_time":477.81,"speaker_name":"Tristan Pelligrino"},{"text":"We need to add like a newsletter plug in or something.","index":105,"end_time":485.65,"speaker_id":2,"start_time":482.53,"speaker_name":"Tristan Pelligrino"},{"text":"You know, it''s just.","index":106,"end_time":486.45,"speaker_id":2,"start_time":485.65,"speaker_name":"Tristan Pelligrino"},{"text":"And sometimes you can install the plugin on Staging, but then like Yoast and Elementor, both examples of that, where the license is attached to the domain and they authenticate based on where it''s deployed.","index":107,"end_time":501.66,"speaker_id":2,"start_time":487.82,"speaker_name":"Tristan Pelligrino"},{"text":"So you would have to like reactivate the license once it goes live.","index":108,"end_time":506.94,"speaker_id":2,"start_time":501.74,"speaker_name":"Tristan Pelligrino"},{"text":"Got it.","index":109,"end_time":507.66,"speaker_id":1,"start_time":507.1,"speaker_name":"Jenny Beightol"},{"text":"Sometimes when we push it to live, you know, like literally that''ll be something we do 30 seconds later.","index":110,"end_time":515.6,"speaker_id":2,"start_time":507.9,"speaker_name":"Tristan Pelligrino"},{"text":"Is after we push, we''ll go in and reactivate Elementor and make sure the license is updated.","index":111,"end_time":521.2,"speaker_id":2,"start_time":515.92,"speaker_name":"Tristan Pelligrino"},{"text":"Excellent.","index":112,"end_time":522.24,"speaker_id":1,"start_time":521.6,"speaker_name":"Jenny Beightol"},{"text":"Okay, cool.","index":113,"end_time":523.04,"speaker_id":3,"start_time":522.24,"speaker_name":"Christine Schulz"},{"text":"That sounds great.","index":114,"end_time":523.84,"speaker_id":1,"start_time":523.04,"speaker_name":"Jenny Beightol"},{"text":"But, yeah, I mean, for the most part, you know, headers and footers are consistent throughout.","index":115,"end_time":529.76,"speaker_id":2,"start_time":526.32,"speaker_name":"Tristan Pelligrino"},{"text":"So those are separate components from.","index":116,"end_time":531.32,"speaker_id":2,"start_time":529.76,"speaker_name":"Tristan Pelligrino"},{"text":"From the page piece.","index":117,"end_time":532.48,"speaker_id":2,"start_time":531.32,"speaker_name":"Tristan Pelligrino"},{"text":"You can see with some of these, there is some.","index":118,"end_time":536,"speaker_id":2,"start_time":534.08,"speaker_name":"Tristan Pelligrino"},{"text":"Some custom layout that we''ve done on top, but for the most part, you know, using Elementor components with standard containers.","index":119,"end_time":546.5,"speaker_id":2,"start_time":536,"speaker_name":"Tristan Pelligrino"},{"text":"So it''s.","index":120,"end_time":547.38,"speaker_id":2,"start_time":546.9,"speaker_name":"Tristan Pelligrino"},{"text":"It''s the newer version of Elementor where everything''s in really, the box containers and, you know, which has the margin and padding around it.","index":121,"end_time":554.14,"speaker_id":2,"start_time":547.38,"speaker_name":"Tristan Pelligrino"},{"text":"So everything like.","index":122,"end_time":555.94,"speaker_id":1,"start_time":554.14,"speaker_name":"Jenny Beightol"},{"text":"So taking the homepage, for example, here, like, we have our three product sections.","index":123,"end_time":562.1,"speaker_id":1,"start_time":556.18,"speaker_name":"Jenny Beightol"},{"text":"Let''s say we introduce a fourth product.","index":124,"end_time":565.3,"speaker_id":1,"start_time":562.66,"speaker_name":"Jenny Beightol"},{"text":"Is it pretty seamless to add another container, like, onto the page?","index":125,"end_time":569.78,"speaker_id":1,"start_time":565.46,"speaker_name":"Jenny Beightol"},{"text":"Yeah, so good question.","index":126,"end_time":571.72,"speaker_id":2,"start_time":570.44,"speaker_name":"Tristan Pelligrino"},{"text":"It depends on, like, how it starts.","index":127,"end_time":574.88,"speaker_id":2,"start_time":573.48,"speaker_name":"Tristan Pelligrino"},{"text":"So let''s say.","index":128,"end_time":575.48,"speaker_id":2,"start_time":574.88,"speaker_name":"Tristan Pelligrino"},{"text":"All right, so it goes right, left.","index":129,"end_time":577.72,"speaker_id":2,"start_time":575.56,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":130,"end_time":578.52,"speaker_id":2,"start_time":578.12,"speaker_name":"Tristan Pelligrino"},{"text":"And so the other one would be on the left side.","index":131,"end_time":580.56,"speaker_id":2,"start_time":578.68,"speaker_name":"Tristan Pelligrino"},{"text":"Right.","index":132,"end_time":580.88,"speaker_id":2,"start_time":580.56,"speaker_name":"Tristan Pelligrino"},{"text":"So you probably copy this component here.","index":133,"end_time":583.08,"speaker_id":2,"start_time":580.88,"speaker_name":"Tristan Pelligrino"},{"text":"So you see this container, and you just duplicate and then drag it below the next one, and then you just change the image and.","index":134,"end_time":593.08,"speaker_id":2,"start_time":583.56,"speaker_name":"Tristan Pelligrino"},{"text":"Yep.","index":135,"end_time":593.64,"speaker_id":0,"start_time":593.08,"speaker_name":"Nina Belina"},{"text":"Okay.","index":136,"end_time":594.12,"speaker_id":1,"start_time":593.64,"speaker_name":"Jenny Beightol"},{"text":"Easy peasy.","index":137,"end_time":594.92,"speaker_id":1,"start_time":594.2,"speaker_name":"Jenny Beightol"},{"text":"Yeah.","index":138,"end_time":595.32,"speaker_id":1,"start_time":594.92,"speaker_name":"Jenny Beightol"},{"text":"I asked because.","index":139,"end_time":596.36,"speaker_id":1,"start_time":595.4,"speaker_name":"Jenny Beightol"},{"text":"And Nina, I had sent this note to you.","index":140,"end_time":598.52,"speaker_id":1,"start_time":596.6,"speaker_name":"Jenny Beightol"},{"text":"Our compliance platform page.","index":141,"end_time":603.17,"speaker_id":1,"start_time":599.97,"speaker_name":"Jenny Beightol"},{"text":"Our engineers are still building our compliance platform as we speak.","index":142,"end_time":607.41,"speaker_id":1,"start_time":603.89,"speaker_name":"Jenny Beightol"},{"text":"However, we still want to launch the product with the new website.","index":143,"end_time":611.57,"speaker_id":1,"start_time":607.57,"speaker_name":"Jenny Beightol"},{"text":"We are planning for a true product launch of that part of our Software in early Q2, but we didn''t want to keep your team from building that page for us.","index":144,"end_time":627.65,"speaker_id":1,"start_time":613.09,"speaker_name":"Jenny Beightol"},{"text":"So I just.","index":145,"end_time":629.33,"speaker_id":1,"start_time":628.53,"speaker_name":"Jenny Beightol"},{"text":"What you just walked through, Tristan, that confirms for me that it will be fairly seamless for us to build upon the compliance page once we get to that part in our product roadmap.","index":146,"end_time":641.41,"speaker_id":1,"start_time":629.41,"speaker_name":"Jenny Beightol"},{"text":"Yeah.","index":147,"end_time":642.05,"speaker_id":2,"start_time":641.65,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s great to hear.","index":148,"end_time":643.25,"speaker_id":1,"start_time":642.05,"speaker_name":"Jenny Beightol"},{"text":"Yeah.","index":149,"end_time":644.45,"speaker_id":2,"start_time":643.97,"speaker_name":"Tristan Pelligrino"},{"text":"You know, for a section like that, be pretty easy to.","index":150,"end_time":646.93,"speaker_id":2,"start_time":644.61,"speaker_name":"Tristan Pelligrino"},{"text":"To update.","index":151,"end_time":647.85,"speaker_id":2,"start_time":647.01,"speaker_name":"Tristan Pelligrino"},{"text":"I mean, and then you can see, like, even this is a whole section or a container in and of itself.","index":152,"end_time":652.81,"speaker_id":2,"start_time":647.85,"speaker_name":"Tristan Pelligrino"},{"text":"You can also add the, like, specific blocks.","index":153,"end_time":656.15,"speaker_id":0,"start_time":652.81,"speaker_name":"Nina Belina"},{"text":"So, for example, if it''s not just a product line, if you have additional text or anything, like, it''s very easy to add on to the page.","index":154,"end_time":663.27,"speaker_id":0,"start_time":656.15,"speaker_name":"Nina Belina"},{"text":"Great, great, great, great.","index":155,"end_time":665.11,"speaker_id":1,"start_time":663.43,"speaker_name":"Jenny Beightol"},{"text":"Okay.","index":156,"end_time":665.75,"speaker_id":1,"start_time":665.19,"speaker_name":"Jenny Beightol"},{"text":"I just.","index":157,"end_time":666.31,"speaker_id":1,"start_time":665.83,"speaker_name":"Jenny Beightol"},{"text":"I wanted confirmation that that''s how everything is being built.","index":158,"end_time":669.55,"speaker_id":1,"start_time":666.31,"speaker_name":"Jenny Beightol"},{"text":"And it sounds like it is, so super.","index":159,"end_time":671.59,"speaker_id":1,"start_time":669.55,"speaker_name":"Jenny Beightol"},{"text":"Yep.","index":160,"end_time":673.27,"speaker_id":2,"start_time":672.71,"speaker_name":"Tristan Pelligrino"},{"text":"All right, so that''s Homepage.","index":161,"end_time":677.19,"speaker_id":2,"start_time":675.43,"speaker_name":"Tristan Pelligrino"},{"text":"Anything else, Christine, that jumps out at.","index":162,"end_time":681.11,"speaker_id":2,"start_time":677.67,"speaker_name":"Tristan Pelligrino"},{"text":"You just like the HubSpot forms and, like, how that looks like?","index":163,"end_time":685.92,"speaker_id":3,"start_time":681.11,"speaker_name":"Christine Schulz"},{"text":"Is it.","index":164,"end_time":686.36,"speaker_id":3,"start_time":685.92,"speaker_name":"Christine Schulz"},{"text":"I''m assuming you just copy and paste the embed code from HubSpot, but is the Functionality of do you have to style it in HubSpot or does the CSS on WordPress overwrite that had it both ways?","index":165,"end_time":701.4,"speaker_id":3,"start_time":687.32,"speaker_name":"Christine Schulz"},{"text":"Sorry.","index":166,"end_time":701.88,"speaker_id":2,"start_time":701.56,"speaker_name":"Tristan Pelligrino"},{"text":"Go ahead, Nina, I''ll let you.","index":167,"end_time":703,"speaker_id":2,"start_time":701.88,"speaker_name":"Tristan Pelligrino"},{"text":"Sorry.","index":168,"end_time":703.56,"speaker_id":0,"start_time":703.08,"speaker_name":"Nina Belina"},{"text":"Usually what we do is we give access to the person who''s doing the integration to HubSpot, for example, for a webpage.","index":169,"end_time":711.84,"speaker_id":0,"start_time":703.72,"speaker_name":"Nina Belina"},{"text":"So it would be how the forms are looking, where they''re situated and then they do the integration to HubSpot.","index":170,"end_time":718.9,"speaker_id":0,"start_time":711.84,"speaker_name":"Nina Belina"},{"text":"So to connect the forms and to connect everything so it works seamlessly.","index":171,"end_time":723.5,"speaker_id":0,"start_time":719.46,"speaker_name":"Nina Belina"},{"text":"So I would maybe suggest just to give the person who''s working on your HubSpot the access to WordPress and they should be able to connect everything.","index":172,"end_time":734.18,"speaker_id":0,"start_time":723.5,"speaker_name":"Nina Belina"},{"text":"Yeah, and he''s definitely, he was definitely asking about that.","index":173,"end_time":741.98,"speaker_id":3,"start_time":735.38,"speaker_name":"Christine Schulz"},{"text":"So.","index":174,"end_time":742.22,"speaker_id":3,"start_time":741.98,"speaker_name":"Christine Schulz"},{"text":"Awesome.","index":175,"end_time":742.86,"speaker_id":3,"start_time":742.22,"speaker_name":"Christine Schulz"},{"text":"Yeah.","index":176,"end_time":744.06,"speaker_id":2,"start_time":743.74,"speaker_name":"Tristan Pelligrino"},{"text":"I mean big picture though, like to integrate a HubSpot form, it would just be an HTML component.","index":177,"end_time":749.26,"speaker_id":2,"start_time":744.06,"speaker_name":"Tristan Pelligrino"},{"text":"So like if you go to.","index":178,"end_time":750.86,"speaker_id":2,"start_time":749.5,"speaker_name":"Tristan Pelligrino"},{"text":"Let me try to.","index":179,"end_time":753.26,"speaker_id":2,"start_time":752.3,"speaker_name":"Tristan Pelligrino"},{"text":"I can give you a random code if you want to stop it.","index":180,"end_time":757.26,"speaker_id":3,"start_time":754.3,"speaker_name":"Christine Schulz"},{"text":"Well, like here.","index":181,"end_time":758.22,"speaker_id":2,"start_time":757.26,"speaker_name":"Tristan Pelligrino"},{"text":"So we.","index":182,"end_time":758.66,"speaker_id":2,"start_time":758.22,"speaker_name":"Tristan Pelligrino"},{"text":"It would just be an HTML snippet.","index":183,"end_time":760.46,"speaker_id":2,"start_time":758.66,"speaker_name":"Tristan Pelligrino"},{"text":"So you would have a container and then you drop this HTML snippet in that container and it''s what we would drop in this HTML snippet is just the HubSpot embed code.","index":184,"end_time":770.59,"speaker_id":2,"start_time":760.62,"speaker_name":"Tristan Pelligrino"},{"text":"And so you can actually style it in HubSpot and we can just use that CSS.","index":185,"end_time":775.15,"speaker_id":2,"start_time":770.91,"speaker_name":"Tristan Pelligrino"},{"text":"It''ll be embedded in line.","index":186,"end_time":776.91,"speaker_id":2,"start_time":775.23,"speaker_name":"Tristan Pelligrino"},{"text":"And so you know, Even if your HubSpot person wants to, you know, put a border around the fields or anything like that, we can just run with that style and it''s very clean that way.","index":187,"end_time":790.51,"speaker_id":2,"start_time":777.23,"speaker_name":"Tristan Pelligrino"},{"text":"And then for example, if you have a HubSpot form and you define in the workflow that after the form is submitted, once it catches that form submission, you would define what the landing page or the redirect page and all that would be handled in HubSpot and you would just need that page in existence on your, your main website.","index":188,"end_time":810.52,"speaker_id":2,"start_time":790.99,"speaker_name":"Tristan Pelligrino"},{"text":"So you know, you just needed like a two page process there.","index":189,"end_time":815.48,"speaker_id":2,"start_time":810.92,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":190,"end_time":816.76,"speaker_id":3,"start_time":816.28,"speaker_name":"Christine Schulz"},{"text":"Yeah, that makes sense.","index":191,"end_time":818.28,"speaker_id":3,"start_time":817.08,"speaker_name":"Christine Schulz"},{"text":"Cool.","index":192,"end_time":821.07,"speaker_id":3,"start_time":820.67,"speaker_name":"Christine Schulz"},{"text":"I think that''s, that''s all I had.","index":193,"end_time":831.07,"speaker_id":3,"start_time":828.43,"speaker_name":"Christine Schulz"},{"text":"Is it easier to give our HubSpot consultant access to the staging site to do all of the form uploads or like how does.","index":194,"end_time":846.04,"speaker_id":3,"start_time":831.47,"speaker_name":"Christine Schulz"},{"text":"Has the best process for that?","index":195,"end_time":847.96,"speaker_id":3,"start_time":846.2,"speaker_name":"Christine Schulz"},{"text":"Yeah, I think we want to get to a certain point where we''re not like because the pages are locked when we''re developing those.","index":196,"end_time":853.88,"speaker_id":2,"start_time":848.44,"speaker_name":"Tristan Pelligrino"},{"text":"So like we just want to make sure that someone doesn''t like because it''s a check in checkout system.","index":197,"end_time":858.48,"speaker_id":2,"start_time":853.88,"speaker_name":"Tristan Pelligrino"},{"text":"So someone checks out a page, they''re working on it.","index":198,"end_time":861.08,"speaker_id":2,"start_time":858.48,"speaker_name":"Tristan Pelligrino"},{"text":"We no One else can really go in there unless we, you know, kick out a person.","index":199,"end_time":866.32,"speaker_id":2,"start_time":861.32,"speaker_name":"Tristan Pelligrino"},{"text":"But then you would lose your work at that point.","index":200,"end_time":868.64,"speaker_id":2,"start_time":866.32,"speaker_name":"Tristan Pelligrino"},{"text":"So it''s kind of like whenever we want to draw a line, the sand, if we feel pretty good that, you know, hey, these pages are set, you know, you could go in, add the form.","index":201,"end_time":877.65,"speaker_id":2,"start_time":868.64,"speaker_name":"Tristan Pelligrino"},{"text":"So it''s just more about communicating when the right time is.","index":202,"end_time":880.93,"speaker_id":2,"start_time":877.81,"speaker_name":"Tristan Pelligrino"},{"text":"Nina, maybe you can speak to like what we have left and where, you know, that, that timing might come into play.","index":203,"end_time":888.769,"speaker_id":2,"start_time":881.89,"speaker_name":"Tristan Pelligrino"},{"text":"Well, at the moment we''ve developed all pages for the staging mode.","index":204,"end_time":895.01,"speaker_id":0,"start_time":889.49,"speaker_name":"Nina Belina"},{"text":"The only one that we have left is the 404 page, so the arrow page.","index":205,"end_time":899.65,"speaker_id":0,"start_time":895.09,"speaker_name":"Nina Belina"},{"text":"And when it comes to everything else, like when we have the feedback and everything is, you know, we have to remove the animations.","index":206,"end_time":907.7,"speaker_id":0,"start_time":900.85,"speaker_name":"Nina Belina"},{"text":"I think that''s one of the things that we mentioned previously.","index":207,"end_time":910.82,"speaker_id":0,"start_time":907.7,"speaker_name":"Nina Belina"},{"text":"I think that for that it would be fine to have somebody access it and do the forms.","index":208,"end_time":918.18,"speaker_id":0,"start_time":912.42,"speaker_name":"Nina Belina"},{"text":"Okay.","index":209,"end_time":919.22,"speaker_id":2,"start_time":918.66,"speaker_name":"Tristan Pelligrino"},{"text":"So it''s right around the corner.","index":210,"end_time":920.34,"speaker_id":2,"start_time":919.22,"speaker_name":"Tristan Pelligrino"},{"text":"We''d be able to do that, Christine.","index":211,"end_time":921.78,"speaker_id":2,"start_time":920.34,"speaker_name":"Tristan Pelligrino"},{"text":"And if you just want to drop that information in Slack, we can set up the user and, you know, get all that, that in place and then we just.","index":212,"end_time":932.39,"speaker_id":2,"start_time":921.78,"speaker_name":"Tristan Pelligrino"},{"text":"I''m trying to think when we go.","index":213,"end_time":933.95,"speaker_id":2,"start_time":932.39,"speaker_name":"Tristan Pelligrino"},{"text":"The one distinction is we''ll, we''ll have copies of Live and the database when we push from Staging.","index":214,"end_time":945.87,"speaker_id":2,"start_time":934.43,"speaker_name":"Tristan Pelligrino"},{"text":"But just one thing to remember is whatever users we create in Staging will get pushed to Live.","index":215,"end_time":953.79,"speaker_id":2,"start_time":946.35,"speaker_name":"Tristan Pelligrino"},{"text":"So like, if, you know, if anyone has entered a new user in Live, and since we''ve been building that user''s not in Staging, they won''t be there, you know, when we push the Live.","index":216,"end_time":967.88,"speaker_id":2,"start_time":954.11,"speaker_name":"Tristan Pelligrino"},{"text":"So just something to think about there.","index":217,"end_time":969.96,"speaker_id":2,"start_time":968.12,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":218,"end_time":971.64,"speaker_id":3,"start_time":971.08,"speaker_name":"Christine Schulz"},{"text":"Yep.","index":219,"end_time":975.92,"speaker_id":2,"start_time":975.48,"speaker_name":"Tristan Pelligrino"},{"text":"But other than that, I''m hoping this is a much better, you know, system for you all to.","index":220,"end_time":981.56,"speaker_id":2,"start_time":975.92,"speaker_name":"Tristan Pelligrino"},{"text":"You should be able to come in here and, and make some, some changes pretty quickly and kind of keep running as a marketing team versus using everything in custom fields and such, which is, it''s really hard to, to, to deal with on the front end.","index":221,"end_time":994.76,"speaker_id":2,"start_time":981.56,"speaker_name":"Tristan Pelligrino"},{"text":"So, yeah, definitely, this is really helpful.","index":222,"end_time":998.84,"speaker_id":3,"start_time":994.76,"speaker_name":"Christine Schulz"},{"text":"Thank you.","index":223,"end_time":999.32,"speaker_id":3,"start_time":998.84,"speaker_name":"Christine Schulz"},{"text":"Appreciate it.","index":224,"end_time":1000.12,"speaker_id":3,"start_time":999.32,"speaker_name":"Christine Schulz"},{"text":"Yeah, for sure.","index":225,"end_time":1000.84,"speaker_id":2,"start_time":1000.28,"speaker_name":"Tristan Pelligrino"},{"text":"If anything comes up, you know, let us know.","index":226,"end_time":1002.6,"speaker_id":2,"start_time":1000.84,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll.","index":227,"end_time":1003.6,"speaker_id":2,"start_time":1003.24,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll try to point you in the right direction where some of that stuff would live and we''ll keep you updated on when we can get the user access, get the forms in place.","index":228,"end_time":1013.77,"speaker_id":2,"start_time":1003.6,"speaker_name":"Tristan Pelligrino"},{"text":"But those should be pretty simple, Christine.","index":229,"end_time":1016.25,"speaker_id":2,"start_time":1014.17,"speaker_name":"Tristan Pelligrino"},{"text":"You know, just dropping an embed code and making sure the container is mobile and responsive.","index":230,"end_time":1022.69,"speaker_id":2,"start_time":1016.25,"speaker_name":"Tristan Pelligrino"},{"text":"And HubSpot''s embed code is.","index":231,"end_time":1026.17,"speaker_id":2,"start_time":1022.69,"speaker_name":"Tristan Pelligrino"},{"text":"So it''s pretty, it''s pretty quick to implement there.","index":232,"end_time":1029.13,"speaker_id":2,"start_time":1026.25,"speaker_name":"Tristan Pelligrino"},{"text":"Yep, sounds good.","index":233,"end_time":1031.13,"speaker_id":3,"start_time":1029.69,"speaker_name":"Christine Schulz"},{"text":"All right, well, thank you.","index":234,"end_time":1034.21,"speaker_id":2,"start_time":1032.25,"speaker_name":"Tristan Pelligrino"},{"text":"Thank you both.","index":235,"end_time":1034.97,"speaker_id":2,"start_time":1034.21,"speaker_name":"Tristan Pelligrino"},{"text":"Yes, of course.","index":236,"end_time":1036.61,"speaker_id":1,"start_time":1035.77,"speaker_name":"Jenny Beightol"},{"text":"We appreciate the time today.","index":237,"end_time":1037.97,"speaker_id":1,"start_time":1036.61,"speaker_name":"Jenny Beightol"},{"text":"This is great.","index":238,"end_time":1038.65,"speaker_id":1,"start_time":1037.97,"speaker_name":"Jenny Beightol"},{"text":"Happy to hear everything.","index":239,"end_time":1039.98,"speaker_id":1,"start_time":1039.18,"speaker_name":"Jenny Beightol"},{"text":"Yeah, we''re getting there.","index":240,"end_time":1041.74,"speaker_id":2,"start_time":1040.62,"speaker_name":"Tristan Pelligrino"},{"text":"I know.","index":241,"end_time":1042.62,"speaker_id":3,"start_time":1042.06,"speaker_name":"Christine Schulz"},{"text":"Home stretch.","index":242,"end_time":1043.98,"speaker_id":1,"start_time":1043.1,"speaker_name":"Jenny Beightol"},{"text":"All right, well, thank you.","index":243,"end_time":1045.5,"speaker_id":3,"start_time":1044.3,"speaker_name":"Christine Schulz"},{"text":"Bye.","index":244,"end_time":1047.78,"speaker_id":0,"start_time":1047.34,"speaker_name":"Nina Belina"},{"text":"Bye.","index":245,"end_time":1048.22,"speaker_id":2,"start_time":1047.78,"speaker_name":"Tristan Pelligrino"}],"dateString":"2026-01-14T18:30:00.000Z","host_email":"tristan.pelligrino@marketersindemand.com","meeting_link":"https://us02web.zoom.us/j/82201978387?pwd=7Ll8Nqvnxxdm75d30YGqXzbQb6PuX9.1","participants":["christine.schulz@encamp.com,tristan.pelligrino@marketersindemand.com,baylee.gunnell@marketersindemand.com,jenny.beightol@encamp.com,nina.belina@marketersindemand.com","christine.schulz@encamp.com","baylee.gunnell@marketersindemand.com","jenny.beightol@encamp.com","nina.belina@marketersindemand.com"],"transcript_url":"https://app.fireflies.ai/view/01KEF078WSDX9DTMHAA51PVEFK","organizer_email":"tristan.pelligrino@marketersindemand.com"}'::jsonb,
    '{"label":"positive","confidence":0.92,"bullets":["Clarified Elementor setup allows future updates like product additions with minimal developer support.","Confirmed HubSpot forms will be added via HTML embeds; styling remains consistent and clean.","Discussed plugin licensing steps; Yoast and Elementor Pro required at go-live, client will purchase.","Established staging-to-live deployment plan; punch list will guide final tasks and plugin activation.","Agreed HubSpot consultant will receive access once final animations and feedback are complete."],"highlights":[{"quote":"That confirms for me that it will be fairly seamless for us to build upon the compliance page","speaker":"Jenny Beightol"},{"quote":"I''m hoping this is a much better... system for you all to... make some... changes pretty quickly","speaker":"Tristan Pelligrino"}],"topics":["launch","integration","delivery","plugins"],"model":"gpt-4-1106-preview","version":1,"generated_at":"2026-01-14T00:00:00Z"}'::jsonb,
    '{"fireflies_summary":{"notes":"## **Website Backend Functionality and Structure**\n\nThe team confirmed the new website backend uses **Elementor with a lightweight WordPress theme** to offer flexible and efficient content updates (01:55).\n\n- **Tristan Pelligrino** detailed the use of Elementor’s built-in components like image carousels and global styling for fonts and colors, minimizing custom code and ensuring easy edits.\n- Global CSS handles site-wide style changes, as **Nina Belina** noted, allowing consistent updates across pages without manual repetition.\n- Standard WordPress features such as version control require **Elementor Pro** for full functionality, and password protection will be handled via lightweight plugins layered on top of the core theme.\n- The approach targets marketing team autonomy, enabling quick changes without deep development, improving over prior custom field complexities (16:15).\n\n## **Plugin Integration and Licensing**\n\nKey plugins like **Yoast SEO** and **Elementor Pro** are planned to be added before site launch, requiring client purchase of licenses (06:11).\n\n- Licenses are domain-specific and must be reactivated immediately after pushing from staging to live to avoid downtime, a process Tristan confirmed will be handled within seconds of launch.\n- Yoast will manage SEO titles, tags, metadata, and 301 redirects cleanly, aligning with the SEO strategy and simplifying ongoing site management.\n- The team will maintain a punch list to track remaining plugin installs and miscellaneous final tasks, ensuring nothing is missed before launch (07:37).\n\n## **Product Page Flexibility and Roadmap Alignment**\n\nThe website structure allows easy expansion of product sections, supporting the rollout of the **compliance platform page** ahead of its early Q2 launch (09:14).\n\n- Jenny Beightol confirmed the current build enables adding new product containers seamlessly by duplicating existing components and updating content.\n- Nina emphasized the ability to add specific blocks like text or images, allowing the marketing team to adapt pages as the product roadmap evolves.\n- Tristan assured that the website will support incremental updates without blocking the live site launch, aligning product development timelines with marketing needs.\n\n## **HubSpot Form Integration and Access Management**\n\nHubSpot forms will be integrated using **HTML embed codes** placed in Elementor containers, allowing styling to be controlled primarily within HubSpot (11:21).\n\n- Nina recommended granting the HubSpot consultant WordPress staging access once pages are stable to manage form setup directly, ensuring proper workflow alignment.\n- Tristan highlighted the importance of coordinating timing to avoid content conflicts during development, as page checkout locks editing for others.\n- User management considerations arose because staging user additions will overwrite live users upon pushing, requiring careful coordination to avoid data loss (15:18).\n\n## **Launch Preparation and Post-Launch Support**\n\nThe team plans a coordinated effort to complete final tasks and ensure smooth transition to live, with clear responsibilities and timelines (07:37).\n\n- Tristan will provide a detailed punch list of remaining items, including plugin activations and miscellaneous fixes, helping Jenny’s team track progress.\n- License reactivations for Elementor and Yoast will occur immediately after going live to prevent any functional gaps.\n- The site is expected to empower the marketing team for quick content updates post-launch, reducing reliance on developers and improving agility (16:15).","outline":null,"keywords":["Elementor","WordPress backend","HubSpot forms","Yoast SEO","password protection plugin","staging environment"],"overview":"- **Website Structure:** New backend uses Elementor with a lightweight WordPress theme for flexible, easy content updates.  \n- **License Requirement:** Yoast SEO and Elementor Pro licenses must be purchased for domain-specific functionality before launch.  \n- **Product Page Flexibility:** Structure allows seamless addition of product sections ahead of early Q2 compliance platform launch.  \n- **HubSpot Integration:** HubSpot forms will be embedded in Elementor, with access management planned to prevent content conflicts.  \n- **Launch Prep:** Detailed punch list for final tasks supports smooth transition to live site, enhancing post-launch marketing agility.","action_items":"\n**Tristan Pelligrino**\nProvide punch list of final tasks and action items for go-live to client marketing team (07:37)\nSet up user access for HubSpot consultant on staging site after development lock and communicate timing to Christine and team (14:49)\nAssist with embedding HubSpot forms using HTML embed codes; ensure container responsiveness and styling compatibility (16:40)\nReactivate Elementor and Yoast plugin licenses immediately after site push to live environment (08:27)\n\n**Christine Schulz**\nShare HubSpot consultant contact details and form embed info with Tristan and Nina to setup access for staging environment (14:49)\n\n**Nina Belina**\nCoordinate timing of locking pages for form integration and manage feedback implementation including animation removal (14:49)\nAssist in granting WordPress access to HubSpot consultant for form integration post-development completion (14:49)\n"},"migrated_from":"contract_meetings","original_id":"c16f81d8-df91-4aea-990e-de7d4b8b64db","master_marketer":{"status":"migrated"}}'::jsonb,
