ame":"Ryan Fisher"},{"text":"For sure it is.","index":265,"end_time":654.44,"speaker_id":3,"start_time":653.77,"speaker_name":"Ryan Fisher"},{"text":"I don''t know, Matt.","index":266,"end_time":655.55,"speaker_id":3,"start_time":654.75,"speaker_name":"Ryan Fisher"},{"text":"I''m kind of thinking the same thing.","index":267,"end_time":657.71,"speaker_id":3,"start_time":655.71,"speaker_name":"Ryan Fisher"},{"text":"When''s it going to come to a neighborhood near us?","index":268,"end_time":660.03,"speaker_id":3,"start_time":657.71,"speaker_name":"Ryan Fisher"},{"text":"I tell you when it''s not going.","index":269,"end_time":661.63,"speaker_id":0,"start_time":660.35,"speaker_name":"Matthew Look"},{"text":"It''s not coming to Sheboygan anytime soon.","index":270,"end_time":663.43,"speaker_id":0,"start_time":661.63,"speaker_name":"Matthew Look"},{"text":"No, no, no, no.","index":271,"end_time":665.47,"speaker_id":3,"start_time":663.43,"speaker_name":"Ryan Fisher"},{"text":"Unless they''re doing a recruitment mission for ICE agents.","index":272,"end_time":669.95,"speaker_id":3,"start_time":665.95,"speaker_name":"Ryan Fisher"},{"text":"You''re exactly right, Ryan.","index":273,"end_time":672.99,"speaker_id":0,"start_time":671.31,"speaker_name":"Matthew Look"},{"text":"You''re 100% right.","index":274,"end_time":674.23,"speaker_id":0,"start_time":672.99,"speaker_name":"Matthew Look"},{"text":"Have you guys seen the commercials yet?","index":275,"end_time":675.87,"speaker_id":3,"start_time":674.23,"speaker_name":"Ryan Fisher"},{"text":"No.","index":276,"end_time":677.15,"speaker_id":4,"start_time":676.75,"speaker_name":"Lindsay Hall"},{"text":"Oh, the ice.","index":277,"end_time":678.11,"speaker_id":3,"start_time":677.39,"speaker_name":"Ryan Fisher"},{"text":"You guys haven''t seen the ICE recruitment commercials yet?","index":278,"end_time":680.19,"speaker_id":3,"start_time":678.11,"speaker_name":"Ryan Fisher"},{"text":"No.","index":279,"end_time":680.86,"speaker_id":4,